// Per-slot texture dimensions (NDS GL_TEXTURE_SIZE_ENUM values)
// These match the iwatodai_dorm_TexSlot enum order.
static const int iwatodai_dorm_tex_widths[1]  = {
    256
};
static const int iwatodai_dorm_tex_heights[1] = {
    256
};

// Call once during scene Init() after setting up VRAM.
// Pass in your pre-allocated textureIds array (size IWATODAI_DORM_TEX_COUNT).
// Pass in your bitmap arrays in slot order (same order as iwatodai_dorm_TexSlot).
inline void Load_iwatodai_dorm(int textureIds[1], const unsigned int* bitmaps[1]) {
    // Slot 0: texture.png
    glGenTextures(1, &textureIds[0]);
    glBindTexture(GL_TEXTURE_2D, textureIds[0]);
    glTexImage2D(GL_TEXTURE_2D, 0, GL_RGB,
        TEXTURE_SIZE_256, TEXTURE_SIZE_256, 0,
        TEXGEN_TEXCOORD | GL_TEXTURE_WRAP_S | GL_TEXTURE_WRAP_T,
        bitmaps[0]);

}

// Call each frame inside your Draw/Update function.
// textureIds must be the same array passed to Load_iwatodai_dorm.
inline void Draw_iwatodai_dorm(const int textureIds[1]) {
    glBindTexture(GL_TEXTURE_2D, textureIds[0]);  // texture.png
    glCallList((u32*)iwatodai_dorm_dl_0);
}

// Call during scene Cleanup().
inline void Delete_iwatodai_dorm(int textureIds[1]) {
    glDeleteTextures(1, textureIds);
}
